public void clicked()
{
    PurchAgreementHeader        purchAgreementHeader,currentHeader;
    FormControl     control = any2Object(this) as FormControl;
    FormRun         formRun = control.formRun();
    FormDataSource      fds = formRun.dataSource();
    FormDataSource      fdsline = formRun.dataSource(4);
    next clicked();

    purchAgreementHeader = fds.cursor();

    RecId currentRecId =  purchAgreementHeader.RecId;

    fds.refresh();
    fds.reread();
    fds.research(true);

    currentHeader = PurchAgreementHeader::find(currentRecId);
    fds.findRecord(currentHeader);

    fdsline.refresh();
    fdsline.reread();


}
